1	/**
2	 * YOU PROBABLY DON'T NEED TO EDIT THIS FILE, UNLESS:
3	 * 1. You want to modify request context (see Part 1)
4	 * 2. You want to create a new middleware or type of procedure (see Part 3)
5	 *
6	 * tl;dr - this is where all the tRPC server stuff is created and plugged in.
7	 * The pieces you will need to use are documented accordingly near the end
8	 */
9	
10	import { db } from "@db/app/client";
11	import { getCachedUserOrgMemberships } from "@repo/app-clerk-cache";
12	import { nanoid } from "@repo/lib";
13	import { trpcMiddleware } from "@sentry/core";
14	import { initTRPC, TRPCError } from "@trpc/server";
15	import { auth } from "@vendor/clerk/server";
16	import { log } from "@vendor/observability/log/next";
17	import { emitJournal, withRequestContext } from "@vendor/observability/request";
18	import superjson from "superjson";
19	import { ZodError } from "zod";
20	
21	/**
22	 * Authentication Context - Discriminated Union
23	 * Represents exactly one authentication method per request
24	 */
25	type AuthContext =
26	  | {
27	      type: "clerk-pending";
28	      userId: string;
29	      // Authenticated but hasn't claimed an organization yet
30	      // Only allowed for onboarding procedures
31	    }
32	  | {
33	      type: "clerk-active";
34	      userId: string;
35	      orgId: string;
36	      // Authenticated and has claimed an organization
37	      // Can access all org-scoped resources
38	    }
39	  | {
40	      type: "unauthenticated";
41	    };
42	
43	/**
44	 * 1. CONTEXT
45	 *
46	 * This section defines the "contexts" that are available in the backend API.
47	 *
48	 * These allow you to access things when processing a request, like the database, the session, etc.
49	 *
50	 * This helper generates the "internals" for a tRPC context. The API handler and RSC clients each
51	 * wrap this and provides the required context.
52	 *
53	 * @see https://trpc.io/docs/server/context
54	 */
55	
56	/**
57	 * Unified tRPC context factory (Clerk auth only)
58	 *
59	 * API key auth is handled by the REST layer (withApiKeyAuth, withDualAuth),
60	 * not tRPC. The CLI uses REST endpoints, not tRPC procedures.
61	 */
62	export const createTRPCContext = async (opts: { headers: Headers }) => {
63	  const clerkSession = await auth({ treatPendingAsSignedOut: false });
64	
65	  if (clerkSession.userId) {
66	    if (clerkSession.orgId) {
67	      return {
68	        auth: {
69	          type: "clerk-active" as const,
70	          userId: clerkSession.userId,
71	          orgId: clerkSession.orgId,
72	        },
73	        db,
74	        headers: opts.headers,
75	      };
76	    }
77	    return {
78	      auth: {
79	        type: "clerk-pending" as const,
80	        userId: clerkSession.userId,
81	      },
82	      db,
83	      headers: opts.headers,
84	    };
85	  }
86	
87	  return {
88	    auth: { type: "unauthenticated" as const },
89	    db,
90	    headers: opts.headers,
91	  };
92	};
93	
94	/**
95	 * 2. INITIALIZATION
96	 *
97	 * This is where the trpc api is initialized, connecting the context and
98	 * transformer
99	 *
100	 * Uses the unified createTRPCContext factory (Clerk auth only).
101	 */
102	const isProduction = process.env.NODE_ENV === "production";
103	
104	const t = initTRPC.context<typeof createTRPCContext>().create({
105	  transformer: superjson,
106	  errorFormatter: ({ shape, error }) => {
107	    // In production, sanitize INTERNAL_SERVER_ERROR messages to prevent credential leaks.
108	    // Procedures that throw TRPCError with specific codes (CONFLICT, BAD_REQUEST, etc.)
109	    // intentionally set user-facing messages, so those are preserved.
110	    const shouldSanitize =
111	      isProduction && error.code === "INTERNAL_SERVER_ERROR";
112	
113	    return {
114	      ...shape,
115	      message: shouldSanitize ? "An unexpected error occurred" : shape.message,
116	      data: {
117	        ...shape.data,
118	        zodError:
119	          error.cause instanceof ZodError ? error.cause.flatten() : null,
120	      },
121	    };
122	  },
123	});
124	
125	const sentryMiddleware = t.middleware(
126	  trpcMiddleware({
127	    attachRpcInput: true,
128	  })
129	);
130	
131	const sentrifiedProcedure = t.procedure.use(sentryMiddleware);
132	
133	/**
134	 * 3. ROUTER & PROCEDURE (THE IMPORTANT BIT)
135	 *
136	 * These are the pieces you use to build your tRPC API. You should import these
137	 * a lot in the /src/server/api/routers folder
138	 */
139	
140	/**
141	 * This is how you create new routers and subrouters in your tRPC API
142	 * @see https://trpc.io/docs/router
143	 */
144	export const createTRPCRouter = t.router;
145	
146	/**
147	 * Create a server-side caller
148	 * @see https://trpc.io/docs/server/server-side-calls
149	 */
150	export const createCallerFactory = t.createCallerFactory;
151	
152	/**
153	 * Middleware for timing procedure execution and adding an artificial delay in development.
154	 *
155	 * You can remove this if you don't like it, but it can help catch unwanted waterfalls by simulating
156	 * network latency that would occur in production but not in local development.
157	 */
158	const observabilityMiddleware = t.middleware(
159	  async ({ next, path, ctx, type }) => {
160	    if (t._config.isDev) {
161	      // artificial delay in dev 100-500ms
162	      const waitMs = Math.floor(Math.random() * 400) + 100;
163	      await new Promise((resolve) => setTimeout(resolve, waitMs));
164	    }
165	
166	    const { result, journal, durationMs } = await withRequestContext(
167	      {
168	        requestId: nanoid(),
169	        ...(ctx.auth.type === "clerk-active" && {
170	          userId: ctx.auth.userId,
171	          orgId: ctx.auth.orgId,
172	        }),
173	        ...(ctx.auth.type === "clerk-pending" && {
174	          userId: ctx.auth.userId,
175	        }),
176	      },
177	      () => next()
178	    );
179	
180	    const meta = {
181	      path,
182	      type,
183	      durationMs,
184	      ok: result.ok,
185	      ...(!result.ok && { errorCode: result.error?.code }),
186	      ...(ctx.auth.type === "clerk-active" && {
187	        userId: ctx.auth.userId,
188	        orgId: ctx.auth.orgId,
189	      }),
190	      ...(ctx.auth.type === "clerk-pending" && {
191	        userId: ctx.auth.userId,
192	      }),
193	    };
194	
195	    if (result.ok) {
196	      log.info("[trpc] procedure completed", meta);
197	    } else {
198	      log.warn("[trpc] procedure failed", meta);
199	    }
200	
201	    emitJournal(journal, { path, durationMs, ok: result.ok });
202	
203	    return result;
204	  }
205	);
206	
207	/**
208	 * Public (unauthed) procedure
209	 *
210	 * This is the base piece you use to build new queries and mutations on your
211	 * tRPC API. It does not guarantee that a user querying is authorized, but you
212	 * can still access user session data if they are logged in
213	 */
214	export const publicProcedure = sentrifiedProcedure.use(observabilityMiddleware);
215	
216	/**
217	 * User-Scoped Procedure
218	 *
219	 * For user-level operations: account settings, profile, list orgs, create org.
220	 * Accepts both clerk-pending (no org) and clerk-active (has org) users.
221	 *
222	 * Use cases:
223	 * - User profile and settings
224	 * - List user's organizations
225	 * - Create new organization
226	 * - User-level integrations (GitHub account connection)
227	 *
228	 * For org-scoped operations (repos, integrations), use `orgScopedProcedure`.
229	 *
230	 * @see https://trpc.io/docs/procedures
231	 */
232	export const userScopedProcedure = sentrifiedProcedure
233	  .use(observabilityMiddleware)
234	  .use(({ ctx, next }) => {
235	    if (ctx.auth.type === "unauthenticated") {
236	      throw new TRPCError({
237	        code: "UNAUTHORIZED",
238	        message: "Authentication required. Please sign in.",
239	      });
240	    }
241	
242	    // Allow both clerk-pending and clerk-active
243	    if (ctx.auth.type !== "clerk-pending" && ctx.auth.type !== "clerk-active") {
244	      throw new TRPCError({
245	        code: "UNAUTHORIZED",
246	        message: "Clerk authentication required",
247	      });
248	    }
249	
250	    return next({
251	      ctx: {
252	        ...ctx,
253	        // Type-safe: either clerk-pending or clerk-active
254	        auth: ctx.auth as Extract<
255	          AuthContext,
256	          { type: "clerk-pending" | "clerk-active" }
257	        >,
258	      },
259	    });
260	  });
261	
262	/**
263	 * Org-Scoped Procedure
264	 *
265	 * For org-level operations: repositories, members, integrations.
266	 * Only accepts clerk-active users (authenticated + has claimed org).
267	 *
268	 * Type-safe: `ctx.auth.orgId` is guaranteed to exist.
269	 *
270	 * Use cases:
271	 * - Repositories (connect, sync)
272	 * - Org members (invite, remove)
273	 * - Org integrations (GitHub org, Slack)
274	 * - Org settings
275	 *
276	 * For user-level operations (profile, create org), use `userScopedProcedure`.
277	 *
278	 * @see https://trpc.io/docs/procedures
279	 */
280	export const orgScopedProcedure = sentrifiedProcedure
281	  .use(observabilityMiddleware)
282	  .use(({ ctx, next }) => {
283	    if (ctx.auth.type === "unauthenticated") {
